import{c as t,Q as o,j as r,m as i}from"./chunks/framework.CdiUUa3G.js";const u=JSON.parse('{"title":"PRD-015 — Mobile App · Capacitor wrapper","description":"","frontmatter":{},"headers":[],"relativePath":"prd/PRD-015.md","filePath":"prd/PRD-015.md"}'),a={name:"prd/PRD-015.md"};function s(n,e,d,l,c,p){return o(),r("div",null,[...e[0]||(e[0]=[i('<h1 id="prd-015-—-mobile-app-·-capacitor-wrapper" tabindex="-1">PRD-015 — Mobile App · Capacitor wrapper <a class="header-anchor" href="#prd-015-—-mobile-app-·-capacitor-wrapper" aria-label="Permalink to &quot;PRD-015 — Mobile App · Capacitor wrapper&quot;">​</a></h1><blockquote><p>Status · Draft v0.3 (4 blocking decisions resolved 2026-05-16) Date · 2026-05-16 Owner · Marko Audiences · curious learner, STEM student, educator, space enthusiast Closes into · RFC-018 (Capacitor mobile integration) Slice gate · v0.8 (post-RFC-017 surface hotspots in v0.7) Why this is a PRD · Orrery already runs in mobile browsers, but a browser tab is the wrong container for the product. PRD-015 commits to <strong>distributing Orrery as a native Android + iOS app via Capacitor</strong>, with the existing SvelteKit web app as the source of truth and the native shell adding only what Google Play and the App Store require: an icon, a splash, a privacy policy, a system share sheet, and the ability to install from a store rather than from a URL bar. The user-value argument is reach (the audience reaches for their phone, not their laptop) and platform legitimacy (an installed app is treated differently from a bookmarked tab). The PRD locks scope to &quot;wrap and ship the same product&quot;; no native screens, no rewrite, no parallel codebase.</p></blockquote><hr><h2 id="problem" tabindex="-1">Problem <a class="header-anchor" href="#problem" aria-label="Permalink to &quot;Problem&quot;">​</a></h2><p>Orrery is a browser-first application that runs well in a mobile browser — Three.js renders in mobile Safari and Chrome WebView, the v0.6 mobile pass shipped a hamburger nav, horizontal-flow layer chips on <code>/explore</code> <code>/earth</code> <code>/moon</code> <code>/mars</code>, a collapsible <code>/fly</code> HUD, a compact <code>/science</code> rail, and footer/CTA clearance — but a browser tab is still the wrong container.</p><p>The 3D solar system, the mission arc, the porkchop plot, the cislunar Earth-centred view, the ISS module-pickability, the Mars surface map: these are experiences, not pages. They belong on a home screen and in an app drawer.</p><p>Mobile browser distribution also limits reach. App-store presence is the discovery channel for Orrery&#39;s audience — students, curious people, educators. The curious person who watched a Mars landing reaches for their phone, not a laptop, and they reach for the app store, not a search engine.</p><p>There is also a capability gap. PWA install on iOS is hidden behind Safari&#39;s share sheet; Android&#39;s &quot;Add to home screen&quot; is more discoverable but still requires a browser visit first. A native wrapper is also the prerequisite for mobile-first features — system share sheet for mission arcs, haptics on trajectory events, native deep links — that a browser tab can&#39;t surface.</p><hr><h2 id="goal" tabindex="-1">Goal <a class="header-anchor" href="#goal" aria-label="Permalink to &quot;Goal&quot;">​</a></h2><p>Ship Orrery as a native application on <strong>Android and iOS in parallel</strong>, distributed via Google Play and the App Store, using Capacitor as the wrapper layer.</p><p>The web application <strong>is</strong> the product. Capacitor provides only the shell.</p><p><strong>Sequencing within the parallel build.</strong> Both platforms are co-equal targets; public store releases happen on the same day. During development, <strong>Android Internal Testing comes online faster</strong> than TestFlight (no provisioning-profile rigmarole, no Apple review for internal testers, $25 one-time vs $99/year), so the practical iteration loop runs Android-first while iOS builds in lock-step for parity testing.</p><hr><h2 id="non-goals" tabindex="-1">Non-goals <a class="header-anchor" href="#non-goals" aria-label="Permalink to &quot;Non-goals&quot;">​</a></h2><ul><li><strong>Not a rewrite.</strong> The SvelteKit application is the source of truth. Capacitor wraps the static <code>build/</code> output — it does not replace any of it.</li><li><strong>Not new screens.</strong> No mobile-only routes; the existing 11 primary nav routes (<code>/explore</code> · <code>/plan</code> · <code>/fly</code> · <code>/missions</code> · <code>/earth</code> · <code>/moon</code> · <code>/mars</code> · <code>/iss</code> · <code>/tiangong</code> · <code>/science</code> · <code>/fleet</code>) plus <code>/credits</code> <code>/library</code> <code>/posters</code> adapt to mobile viewports as already shipped in v0.6.</li><li><strong>Not native UI components.</strong> No UIKit, no Jetpack Compose, no native nav. The Capacitor WebView renders the SvelteKit app as-is.</li><li><strong>Not background processing.</strong> No background fetch, no push notifications, no background location. Launch-window countdowns are a Phase 3 consideration.</li><li><strong>Not enterprise distribution.</strong> Public Google Play + public App Store only. MDM / enterprise profiles out of scope.</li><li><strong>Not a parallel data layer.</strong> Mission JSON ships bundled with the app. Updates ride on app-version submissions plus the existing PWA service worker (autoUpdate per the May 2026 PWA refresh).</li></ul><hr><h2 id="requirements" tabindex="-1">Requirements <a class="header-anchor" href="#requirements" aria-label="Permalink to &quot;Requirements&quot;">​</a></h2><h3 id="must-have" tabindex="-1">Must have <a class="header-anchor" href="#must-have" aria-label="Permalink to &quot;Must have&quot;">​</a></h3><table tabindex="0"><thead><tr><th>ID</th><th>Requirement</th></tr></thead><tbody><tr><td>M1</td><td>Installs from Google Play on Android 10+ and the App Store on iOS 16+</td></tr><tr><td>M2</td><td>All 14 routes (11 primary + 3 read-only) render correctly at 360 px–412 px viewport widths (common Android range)</td></tr><tr><td>M3</td><td>All 14 routes render correctly at 375 px–430 px viewport widths (iPhone SE through iPhone 15 Pro Max)</td></tr><tr><td>M4</td><td>Three.js r128 (per ADR-001) renders in Chromium WebView (Android 10+) and WKWebView (iOS 16+) for all 7 3D scenes: <code>/explore</code>, <code>/fly</code> heliocentric, <code>/fly</code> cislunar (per ADR-058), <code>/earth</code>, <code>/moon</code>, <code>/mars</code>, <code>/iss</code>, <code>/tiangong</code></td></tr><tr><td>M5</td><td>App functions fully offline. Already true via the v0.6 PWA service worker (ADR-029); must be verified in the Capacitor container on both platforms</td></tr><tr><td>M6</td><td>The Lambert worker (per ADR-022) runs correctly in the WebView context on both platforms</td></tr><tr><td>M7</td><td>Touch interactions work: orbit (one-finger drag), zoom (pinch), tap (object selection), per-route hit-testing via <code>window.__pickAt</code> (ADR-056)</td></tr><tr><td>M8</td><td>Bottom-sheet panel pattern (already shipped per ADR-018) is verified in the Capacitor WebView</td></tr><tr><td>M9</td><td>App icons + splash screens meet Google Play + App Store submission requirements</td></tr><tr><td>M10</td><td>Privacy policy page exists and is linked from each store listing</td></tr><tr><td>M11</td><td>Bundle-size strategy is documented + measured. Naive build is ~355 MB (fleet galleries + science diagrams + 14-locale overlays + textures); RFC-018 § bundle-strategy proposes a stripped on-device baseline with optional fetch-on-demand for large galleries. Required before <strong>either</strong> store submission</td></tr><tr><td>M12</td><td>The single <code>orrery_locale</code> cookie permitted by ADR-057 works in the Capacitor WebView on both platforms (or a Capacitor Preferences shim is added)</td></tr></tbody></table><h3 id="should-have" tabindex="-1">Should have <a class="header-anchor" href="#should-have" aria-label="Permalink to &quot;Should have&quot;">​</a></h3><table tabindex="0"><thead><tr><th>ID</th><th>Requirement</th></tr></thead><tbody><tr><td>S1</td><td>Native share-sheet integration via <code>@capacitor/share</code> — &quot;Share this mission arc&quot; surfaces a native Android / iOS sheet</td></tr><tr><td>S2</td><td>Haptic feedback on mission events (TLI confirmed, Mars arrival) via <code>@capacitor/haptics</code></td></tr><tr><td>S3</td><td>Status bar / system bar styling matches <code>--color-bg</code> (<code>#04040c</code>) on both platforms — no white flash between launch and first paint</td></tr><tr><td>S4</td><td>Safe-area insets respected — Android gesture nav bar + status bar; iOS notch + Dynamic Island + home indicator</td></tr><tr><td>S5</td><td>App state preserved across background/foreground cycle — no full reload, WebGL context restored if lost (more critical on iOS WKWebView than Android Chromium)</td></tr><tr><td>S6</td><td>Deep links work — <code>orrery://fly?mission=curiosity</code> opens the mission-arc screen directly. Android App Links + iOS Universal Links (<code>https://chipi.github.io/orrery/fly?mission=curiosity</code>) deferred to Phase 3</td></tr></tbody></table><h3 id="will-not-have-this-phase" tabindex="-1">Will not have (this phase) <a class="header-anchor" href="#will-not-have-this-phase" aria-label="Permalink to &quot;Will not have (this phase)&quot;">​</a></h3><ul><li>Push notifications for launch-window alerts</li><li>Background fetch for mission data updates (PWA autoUpdate covers refresh-on-next-launch)</li><li>Cloud sync for saved missions (Google Drive / iCloud)</li><li>Wear OS / Apple Watch companion</li><li>Widgets (Android / iOS)</li><li>In-app purchases of any kind</li><li>AR / spatial-anchored views (separate ADR if pursued)</li></ul><hr><h2 id="what-s-already-shipped-mobile-readiness-inventory" tabindex="-1">What&#39;s already shipped (mobile-readiness inventory) <a class="header-anchor" href="#what-s-already-shipped-mobile-readiness-inventory" aria-label="Permalink to &quot;What&#39;s already shipped (mobile-readiness inventory)&quot;">​</a></h2><p>Tasks delivered in the v0.6 mobile-pass that PRD-015 inherits:</p><table tabindex="0"><thead><tr><th>Shipped</th><th>Where</th><th>Notes</th></tr></thead><tbody><tr><td>Hamburger nav drawer ≤ 500 px</td><td>commit <code>5f4cc05a</code></td><td>All 11 primary routes accessible; locale picker + lens + contrast toggles next to it</td></tr><tr><td>Horizontal layer-filter chip flow</td><td>commit <code>5f4cc05a</code></td><td>First chip stays anchored; remaining chips wrap rightward instead of stacking vertically</td></tr><tr><td><code>/fly</code> HUD collapsible panels</td><td>commit <code>4addaca9e</code> + <code>0020f128b</code></td><td>Five panel toggles in a top-right strip — HUD, CAPCOM, Flight Director, Layers, Conics</td></tr><tr><td><code>/science</code> compact rail</td><td>task #117</td><td>Right rail shrinks from 70 % viewport to a tight nav strip</td></tr><tr><td>Footer / CTA clearance</td><td>task #115</td><td>Persistent bottom-right footer doesn&#39;t overlap landing-page or <code>/plan</code> action buttons</td></tr><tr><td>Per-planet pill colors</td><td>task #112</td><td>Mars red / Earth blue / Moon grey / Explore teal — visual distinction without relying on placement</td></tr><tr><td>Bottom-sheet panel pattern</td><td>ADR-018</td><td>Right drawer on desktop; bottom sheet ≤ 768 px, swipe-down to dismiss</td></tr><tr><td>Touch readiness signals</td><td>ADR-056</td><td><code>window.__pickAt(x, y)</code> test hook + <code>data-route-ready</code> + <code>data-loading</code> attributes on every canvas route</td></tr></tbody></table><p>The mobile viewport adaptation work that earlier drafts of this PRD pre-empted is <strong>already done</strong>. PRD-015&#39;s primary work is the <strong>wrap + distribute</strong> layer.</p><hr><h2 id="distribution" tabindex="-1">Distribution <a class="header-anchor" href="#distribution" aria-label="Permalink to &quot;Distribution&quot;">​</a></h2><h3 id="android-—-google-play-first-to-ship" tabindex="-1">Android — Google Play (first to ship) <a class="header-anchor" href="#android-—-google-play-first-to-ship" aria-label="Permalink to &quot;Android — Google Play (first to ship)&quot;">​</a></h3><p>Less strict than Apple for educational content; faster to iterate on.</p><ul><li>Target API level 35 (Android 15) as of the August 2025 Play requirement; revisit before submission.</li><li>Privacy policy required (links to a page hosted on <code>chipi.github.io</code>).</li><li>Listing category: <strong>Education</strong>.</li><li><strong>Internal Testing</strong> track is available without a public listing — useful for the first physical-device runs before promoting to Production.</li><li><strong>Closed Testing</strong> for an external test cohort (≥ 12 testers, 14-day opt-in) when needed before Production.</li></ul><p>Expected review cycle: 1 submission, automated review passes within hours for educational content.</p><h3 id="ios-—-app-store" tabindex="-1">iOS — App Store <a class="header-anchor" href="#ios-—-app-store" aria-label="Permalink to &quot;iOS — App Store&quot;">​</a></h3><p>Apple scrutinises web-wrapper apps. Acceptance criteria for a web-app-as-native:</p><ul><li>The app must provide clear educational value beyond pointing at a URL. Orrery qualifies: 11 primary routes, 85-section science encyclopedia, 137-entry fleet, 71 hand-authored SVG diagrams, real Keplerian + Lambert physics, fully offline-capable.</li><li>Must not be a thin wrapper around a website that could be accessed in Safari. Orrery&#39;s offline capability + native integrations (Share, Haptics) + bundled-data model distinguish it from a Safari bookmark.</li><li>Privacy policy required. Orrery collects no personal data per ADR-057 + the project&#39;s privacy stance; the policy states this explicitly.</li><li>Listing category: <strong>Education</strong> primary, <strong>Reference</strong> secondary.</li></ul><p>Expected review cycle: 1–2 submissions before approval. Apple commonly requests screenshots proving offline functionality.</p><h3 id="store-metadata-both" tabindex="-1">Store metadata (both) <a class="header-anchor" href="#store-metadata-both" aria-label="Permalink to &quot;Store metadata (both)&quot;">​</a></h3><ul><li>App name: <strong>Orrery — Solar System Explorer</strong></li><li>Subtitle (iOS) / Short description (Play): <strong>Mission simulator + orbital mechanics</strong></li><li>Long description: adapted from the docs landing (<code>docs/index.md</code>)</li><li>Screenshots: 8–10 per device class (Android phone, Android tablet, iPhone, iPad) — pull from <code>docs/screenshots/</code> (already curated for the README + user guide)</li><li>Privacy policy URL: hosted at <code>https://chipi.github.io/orrery/privacy</code></li><li>Keywords (iOS): solar system, orbital mechanics, Mars, mission simulator, space, NASA, astronomy, education, Apollo, ISS</li></ul><hr><h2 id="success-criteria" tabindex="-1">Success criteria <a class="header-anchor" href="#success-criteria" aria-label="Permalink to &quot;Success criteria&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Criterion</th><th>Measure</th></tr></thead><tbody><tr><td>Ships on both stores</td><td>Google Play listing live + App Store listing live</td></tr><tr><td>Offline verified</td><td>All 14 routes function with no network on a physical device (airplane mode test)</td></tr><tr><td>Three.js verified</td><td>60 fps orbit rendering on a mid-range Android (Snapdragon 778G or equivalent) and iPhone 12 (A14); 30 fps acceptable on <code>/iss</code> + <code>/tiangong</code> (heaviest scenes)</td></tr><tr><td>Lambert worker</td><td><code>/plan</code> porkchop renders within 5 s on the target devices for a single destination</td></tr><tr><td>Touch interactions</td><td>Orbit, zoom, object selection, panel-tab switching all work correctly on touch screens on both platforms</td></tr><tr><td>Cislunar view</td><td><code>/fly?mission=apollo11</code> switches to the cislunar Earth-centred camera correctly per ADR-058</td></tr><tr><td>App store rating</td><td>No forced rejections due to wrapper-policy violations</td></tr><tr><td>Bundle size</td><td>Install size ≤ 80 MB after the bundle-strategy work in RFC-018</td></tr><tr><td>PWA continuity</td><td>Service worker registers and <code>autoUpdate</code> works inside the WebView so bundled-asset refresh on next launch is silent (matches the May 2026 PWA refresh decision)</td></tr></tbody></table><hr><h2 id="dependencies-sequencing" tabindex="-1">Dependencies + sequencing <a class="header-anchor" href="#dependencies-sequencing" aria-label="Permalink to &quot;Dependencies + sequencing&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Dependency</th><th>Status</th><th>Notes</th></tr></thead><tbody><tr><td>RFC-017 / PRD-014 (Surface Hotspots) shipped</td><td>Required first</td><td>Mobile distribution should ship the <strong>best-case desktop experience</strong> of landing-site exploration first, not a degraded mid-pass version. v0.7 lands the Mars/Moon hi-res imagery + per-mission 3D models; v0.8 wraps for mobile</td></tr><tr><td>Privacy policy page</td><td>Required before either store submission</td><td>Static HTML page in <code>static/privacy.html</code> (or a SvelteKit <code>/privacy</code> route) — content is short because no data is collected</td></tr><tr><td>Google Play developer account</td><td>Required</td><td>$25 one-time</td></tr><tr><td>Apple Developer account</td><td>Required</td><td>$99 / yr</td></tr><tr><td>App icon design</td><td>Required</td><td>See open question Q4</td></tr><tr><td>Bundle-size reduction strategy</td><td>Required before either store submission</td><td>RFC-018 § bundle-strategy proposes the cuts</td></tr><tr><td>Mobile-viewport UXS update</td><td>Optional</td><td>The v0.6 mobile work shipped without a dedicated UXS; documenting the patterns retroactively (similar to how ADR-052/053/054 documented Fleet retrospectively) is a clean-up task</td></tr></tbody></table><hr><h2 id="resolved-decisions" tabindex="-1">Resolved decisions <a class="header-anchor" href="#resolved-decisions" aria-label="Permalink to &quot;Resolved decisions&quot;">​</a></h2><p><em>All four blocking questions resolved 2026-05-16. Tracked here for the audit trail; new questions go below.</em></p><ol><li><p><strong>Bundle-size strategy — RESOLVED.</strong> Ship RFC-018 §4 slim plan: 4K planet textures (mobile only), lazy-load 11 non-default locales, 256-px fleet thumbnails with hero-quality images streaming from <code>chipi.github.io</code> on tap. Target ~85 MB installed — well under PRD M11 ceiling (150 MB) and iOS OTA cap (200 MB). Three Vite-config branches gated by <code>MOBILE=1</code>; the browser deploy is unaffected.</p></li><li><p><strong>Data-update mechanism — RESOLVED.</strong> PWA service worker is <strong>disabled</strong> under Capacitor for v1.0 (RFC-018 §8.2). Content updates require a Play / App Store release. Trade-off accepted to dodge App Store §2.5.2 review surprises on the first ship; revisit network-aware SW (RFC-018 §8.1) as a v1.1 ADR if content-update friction surfaces.</p></li><li><p><strong>Tablet — RESOLVED.</strong> Ship as-is for v1.0. Desktop layout fits 1024+ reasonably (<code>/explore</code>, <code>/missions</code>, <code>/science</code>, <code>/fly</code>); no new breakpoint code. Mark tablets as &quot;supported, not optimised&quot; in the Play / App Store listings. Revisit after first physical-device testing.</p></li><li><p><strong>iOS code-signing — RESOLVED.</strong> Marko owns the Apple Developer membership (personal account, $99/yr). Listed as the developer on the App Store. Resolution applies whenever iOS submission begins (Android Google Play ships first regardless).</p></li></ol><h2 id="open-questions" tabindex="-1">Open questions <a class="header-anchor" href="#open-questions" aria-label="Permalink to &quot;Open questions&quot;">​</a></h2><ol start="5"><li><p><strong>App icon design.</strong> The Bebas Neue wordmark doesn&#39;t translate to a 60×60 px home-screen icon. Options:</p><ul><li>Stylised orrery-as-clockwork-model (concentric rings + a planet)</li><li>Lambert porkchop shape (the V-shape that&#39;s the project&#39;s most distinctive visual)</li><li>Simple star + ring on <code>#04040c</code></li></ul><p>Open design task; not blocking until after v0.7 work lands.</p></li><li><p><strong>Internal Testing cohorts.</strong> Need at least 5 Android testers (range: Pixel through Galaxy mid-range) and ~5 iOS testers (range: SE through Pro Max) with real devices. Recruitment plan TBD — likely &quot;ship to Internal Testing track + post in chipi org channels&quot; rather than active recruiting.</p></li><li><p><strong>Per-scene WebGL context-loss restore (7 scenes).</strong> RFC-018 §11.2 requires a small <code>reinit()</code> factor-out on <code>/explore</code>, <code>/fly</code> (heliocentric), <code>/fly</code> (cislunar per ADR-058), <code>/earth</code>, <code>/moon</code>, <code>/mars</code>, <code>/iss</code>, <code>/tiangong</code>. Scope as 7 sub-tasks under M5 when implementation begins; not an architectural decision.</p></li></ol><hr><p><em>Orrery · PRD-015 · Mobile App — Capacitor Wrapper · May 2026</em><em>See also: <a href="./../rfc/RFC-018">RFC-018</a> · <a href="./PRD-014">PRD-014 Surface Hotspots</a> · <a href="./../adr/ADR-018">ADR-018 Mobile-first design</a> · <a href="./../adr/ADR-029">ADR-029 Service worker / PWA</a> · <a href="./../adr/ADR-057">ADR-057 Locale cookie carve-out</a> · <a href="./../adr/ADR-058">ADR-058 Cislunar second camera</a></em></p>',55)])])}const b=t(a,[["render",s]]);export{u as __pageData,b as default};
